class _MyAppState extends State<MyApp> {
  StreamSubscription? _sub;

  @override
  void initState() {
    super.initState();
    initPlatformState();
  }

  Future<void> initPlatformState() async {
    // Attach a listener to the link stream
    _sub = getLinksStream().listen((String? url) {
      if (url != null) {
        handleDeepLink(url);
      }
    });

    // Handle initial deep link when app is opened directly from the link
    try {
      final String? initialLink = await getInitialLink();
      if (initialLink != null) {
        handleDeepLink(initialLink);
      }
    } on PlatformException {
      print('Failed to get initial link.');
    }
  }

  void handleDeepLink(String url) {
    final Uri uri = Uri.parse(url);

    switch (uri.host) {
      case 'profile':
        final String? userId = uri.pathSegments.firstOrNull;
        Navigator.push(
          context,
          MaterialPageRoute(builder: (_) => ProfileScreen(userId: userId)),
        );
        break;
      case 'payment':
        if (uri.path.endsWith('confirm')) {
          Navigator.push(
            context,
            MaterialPageRoute(builder: (_) => PaymentConfirmScreen()),
          );
        }
        break;
    }
  }

  @override
  void dispose() {
    _sub?.cancel();
    super.dispose();
